/**
 * Sample License Generator for Testing
 * 
 * This script creates sample licenses for testing the license system.
 * In production, this would be a secure vendor-side tool.
 */

const forge = require('node-forge')
const fs = require('fs')
const path = require('path')

// Load the private key (generated by generate-rsa-keys.cjs)
const privateKeyPath = path.join(__dirname, '..', 'keys', 'private-key.pem')

if (!fs.existsSync(privateKeyPath)) {
  console.error('❌ Private key not found. Run "node scripts/generate-rsa-keys.cjs" first.')
  process.exit(1)
}

const privateKeyPem = fs.readFileSync(privateKeyPath, 'utf8')
const privateKey = forge.pki.privateKeyFromPem(privateKeyPem)

/**
 * Sign license payload with RSA private key
 */
function signLicense(payload) {
  // Convert payload to JSON string
  const payloadString = JSON.stringify(payload)
  
  // Create SHA-256 hash
  const md = forge.md.sha256.create()
  md.update(payloadString, 'utf8')
  
  // Sign the hash
  const signature = privateKey.sign(md)
  
  // Encode signature as base64
  const signatureBase64 = forge.util.encode64(signature)
  
  // Combine payload and signature
  const licenseKey = Buffer.from(JSON.stringify({
    payload: payloadString,
    signature: signatureBase64
  })).toString('base64')
  
  return licenseKey
}

/**
 * Create sample licenses for testing
 */
function createSampleLicenses() {
  console.log('🔐 Creating Sample Licenses for Testing...\n')
  
  // Get current machine ID for testing
  const machineId = 'LND-0AC1DF443381F8F2' // Actual machine ID for this system
  
  const licenses = [
    {
      name: 'Trial License',
      payload: {
        product: 'LaundryPro',
        version: '1.0.0',
        machineId: machineId,
        issuedTo: 'Test User',
        email: 'test@example.com',
        licenseType: 'TRIAL',
        issuedAt: new Date().toISOString(),
        expiresAt: new Date(Date.now() + 14 * 24 * 60 * 60 * 1000).toISOString(), // 14 days
        features: ['basic', 'reports'],
        maxUsers: 1,
        licenseId: 'TRIAL-001',
        vendorId: 'LAUNDRY-VENDOR'
      }
    },
    {
      name: 'Annual License',
      payload: {
        product: 'LaundryPro',
        version: '1.0.0',
        machineId: machineId,
        issuedTo: 'ABC Laundry Services',
        email: 'contact@abclaundry.com',
        licenseType: 'ANNUAL',
        issuedAt: new Date().toISOString(),
        expiresAt: new Date(Date.now() + 365 * 24 * 60 * 60 * 1000).toISOString(), // 1 year
        features: ['basic', 'reports', 'backup', 'multi-user'],
        maxUsers: 5,
        licenseId: 'ANNUAL-001',
        vendorId: 'LAUNDRY-VENDOR'
      }
    },
    {
      name: 'Lifetime License',
      payload: {
        product: 'LaundryPro',
        version: '1.0.0',
        machineId: machineId,
        issuedTo: 'Premium Customer',
        email: 'premium@example.com',
        licenseType: 'LIFETIME',
        issuedAt: new Date().toISOString(),
        expiresAt: null, // No expiry
        features: ['basic', 'reports', 'backup', 'multi-user', 'premium'],
        maxUsers: 10,
        licenseId: 'LIFETIME-001',
        vendorId: 'LAUNDRY-VENDOR'
      }
    }
  ]
  
  // Create licenses directory
  const licensesDir = path.join(__dirname, '..', 'sample-licenses')
  if (!fs.existsSync(licensesDir)) {
    fs.mkdirSync(licensesDir, { recursive: true })
  }
  
  // Generate and save licenses
  licenses.forEach((license, index) => {
    console.log(`📄 Creating ${license.name}...`)
    
    const licenseKey = signLicense(license.payload)
    
    // Save to file
    const filename = `${license.name.toLowerCase().replace(/\s+/g, '-')}.txt`
    const filepath = path.join(licensesDir, filename)
    
    const content = `${license.name}
${'='.repeat(license.name.length)}

License Key:
${licenseKey}

Details:
- Issued To: ${license.payload.issuedTo}
- Email: ${license.payload.email}
- Type: ${license.payload.licenseType}
- Machine ID: ${license.payload.machineId}
- Features: ${license.payload.features.join(', ')}
- Max Users: ${license.payload.maxUsers}
- Issued: ${new Date(license.payload.issuedAt).toLocaleDateString()}
- Expires: ${license.payload.expiresAt ? new Date(license.payload.expiresAt).toLocaleDateString() : 'Never'}

Usage:
Copy the license key above and paste it into the application's activation screen.
`
    
    fs.writeFileSync(filepath, content)
    console.log(`   ✅ Saved to: ${filepath}`)
  })
  
  console.log('\n🎯 Sample licenses created successfully!')
  console.log('\n📋 Next Steps:')
  console.log('   1. Use these license keys to test the activation system')
  console.log('   2. Copy a license key from the sample-licenses/ directory')
  console.log('   3. Paste it into the application activation screen')
  console.log('   4. Test different license types and expiry scenarios')
  console.log('\n⚠️  Note: These are test licenses with a placeholder machine ID')
  console.log('   For real testing, update the machineId in this script with your actual machine ID')
}

// Run the license creation
createSampleLicenses()